package com.chaobo.scm.supplier.infrastructure.persistence.quote;import org.apache.ibatis.annotations.*;import java.time.*;import java.math.*;import java.util.*;
@Mapper public interface SupplierQuoteMapper{record QuoteRow(long id,String no,long supplierId,Long rfqId,String rfqNo,String currency,LocalDate from,LocalDate to,int status,String reason,String ref,int version){}record LineRow(long id,long quoteId,String sku,BigDecimal qty,BigDecimal price,BigDecimal tax,int days,BigDecimal moq){}@Select("SELECT quote_id id,quote_no no,supplier_id supplierId,rfq_id rfqId,rfq_no rfqNo,currency,valid_from `from`,valid_to `to`,quote_status status,rejection_reason reason,price_agreement_ref ref,version FROM sup_supplier_quote WHERE quote_id=#{id} AND deleted=0")QuoteRow quote(long id);@Select("SELECT quote_line_id id,quote_id quoteId,sku_code sku,quote_qty qty,unit_price price,tax_rate tax,delivery_days days,moq FROM sup_supplier_quote_line WHERE quote_id=#{id} AND deleted=0")List<LineRow> lines(long id);@Insert("INSERT INTO sup_supplier_quote(quote_id,quote_no,supplier_id,rfq_id,rfq_no,currency,valid_from,valid_to,quote_status,rejection_reason,price_agreement_ref,created_by,updated_by,version,deleted) VALUES(#{q.id},#{q.no},#{q.supplierId},#{q.rfqId},#{q.rfqNo},#{q.currency},#{q.from},#{q.to},#{q.status},#{q.reason},#{q.ref},#{operator},#{operator},#{q.version},0)")void insert(@Param("q")QuoteRow q,@Param("operator")long operator);@Update("UPDATE sup_supplier_quote SET valid_from=#{q.from},valid_to=#{q.to},quote_status=#{q.status},rejection_reason=#{q.reason},price_agreement_ref=#{q.ref},updated_by=#{operator},version=#{q.version} WHERE quote_id=#{q.id} AND version=#{expected} AND deleted=0")int update(@Param("q")QuoteRow q,@Param("expected")int expected,@Param("operator")long operator);@Insert("INSERT INTO sup_supplier_quote_line(quote_line_id,quote_id,sku_code,quote_qty,unit_price,tax_rate,delivery_days,moq,version,deleted) VALUES(#{l.id},#{l.quoteId},#{l.sku},#{l.qty},#{l.price},#{l.tax},#{l.days},#{l.moq},0,0)")void insertLine(@Param("l")LineRow l);@Update("UPDATE sup_supplier_quote_line SET sku_code=#{l.sku},quote_qty=#{l.qty},unit_price=#{l.price},tax_rate=#{l.tax},delivery_days=#{l.days},moq=#{l.moq},deleted=0,version=version+1 WHERE quote_line_id=#{l.id} AND quote_id=#{l.quoteId}")int updateLine(@Param("l")LineRow l);@Update("<script>UPDATE sup_supplier_quote_line SET deleted=1,version=version+1 WHERE quote_id=#{quoteId} AND deleted=0 <if test='ids!=null and !ids.isEmpty()'>AND quote_line_id NOT IN <foreach collection='ids' item='id' open='(' separator=',' close=')'>#{id}</foreach></if></script>")void deleteMissingLines(@Param("quoteId")long quoteId,@Param("ids")List<Long> ids);@Select("SELECT quote_id FROM sup_supplier_quote WHERE quote_status IN (1,2,3) AND valid_to<CURDATE() AND deleted=0")List<Long> expiredIds();@Select("<script>SELECT COUNT(*) FROM sup_supplier_quote WHERE deleted=0 <if test='supplierId!=null'>AND supplier_id=#{supplierId}</if><if test='status!=null'>AND quote_status=#{status}</if><if test='keyword!=null and keyword!=\"\"'>AND (quote_no LIKE CONCAT('%',#{keyword},'%') OR rfq_no LIKE CONCAT('%',#{keyword},'%'))</if></script>")long count(@Param("supplierId")Long supplierId,@Param("status")Integer status,@Param("keyword")String keyword);@Select("<script>SELECT quote_id id,quote_no no,supplier_id supplierId,rfq_id rfqId,rfq_no rfqNo,currency,valid_from `from`,valid_to `to`,quote_status status,rejection_reason reason,price_agreement_ref ref,version FROM sup_supplier_quote WHERE deleted=0 <if test='supplierId!=null'>AND supplier_id=#{supplierId}</if><if test='status!=null'>AND quote_status=#{status}</if><if test='keyword!=null and keyword!=\"\"'>AND (quote_no LIKE CONCAT('%',#{keyword},'%') OR rfq_no LIKE CONCAT('%',#{keyword},'%'))</if> ORDER BY updated_at DESC LIMIT #{offset},#{size}</script>")List<QuoteRow> page(@Param("supplierId")Long supplierId,@Param("status")Integer status,@Param("keyword")String keyword,@Param("offset")int offset,@Param("size")int size);}
